import org.springframework.stereotype.Controller;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.PostMapping;
import org.springframework.web.bind.annotation.RequestParam;
import org.springframework.security.core.Authentication;
import org.springframework.security.core.context.SecurityContextHolder;
import org.springframework.security.web.authentication.logout.SecurityContextLogoutHandler;

import javax.servlet.http.HttpServletRequest;
import javax.servlet.http.HttpServletResponse;
import java.io.IOException;
import java.net.URI;
import java.net.URISyntaxException;
import java.util.Arrays;
import java.util.List;

@Controller
public class LogoutController {

    private static final List<String> ALLOWED_DOMAINS = Arrays.asList(
        "example.com",
        "app.example.com",
        "portal.example.com"
    );

    private static final String DEFAULT_REDIRECT_URL = "/login";

    @PostMapping("/logout")
    public void logout(
            @RequestParam(value = "next", required = false) String next,
            HttpServletRequest request,
            HttpServletResponse response) throws IOException {
        
        Authentication auth = SecurityContextHolder.getContext().getAuthentication();
        if (auth != null) {
            new SecurityContextLogoutHandler().logout(request, response, auth);
        }

        String redirectUrl = validateAndSanitizeRedirectUrl(next);
        response.sendRedirect(redirectUrl);
    }

    @GetMapping("/logout")
    public void logoutGet(
            @RequestParam(value = "next", required = false) String next,
            HttpServletRequest request,
            HttpServletResponse response) throws IOException {
        
        Authentication auth = SecurityContextHolder.getContext().getAuthentication();
        if (auth != null) {
            new SecurityContextLogoutHandler().logout(request, response, auth);
        }

        String redirectUrl = validateAndSanitizeRedirectUrl(next);
        response.sendRedirect(redirectUrl);
    }

    private String validateAndSanitizeRedirectUrl(String next) {
        if (next == null || next.trim().isEmpty()) {
            return DEFAULT_REDIRECT_URL;
        }

        next = next.trim();

        if (next.contains("\r") || next.contains("\n")) {
            return DEFAULT_REDIRECT_URL;
        }

        if (next.toLowerCase().startsWith("javascript:") ||
            next.toLowerCase().startsWith("data:") ||
            next.toLowerCase().startsWith("vbscript:")) {
            return DEFAULT_REDIRECT_URL;
        }

        if (next.startsWith("/") && !next.startsWith("//")) {
            return next;
        }

        try {
            URI uri = new URI(next);
            
            if (!uri.isAbsolute()) {
                return DEFAULT_REDIRECT_URL;
            }

            String scheme = uri.getScheme();
            if (scheme == null || (!scheme.equalsIgnoreCase("http") && !scheme.equalsIgnoreCase("https"))) {
                return DEFAULT_REDIRECT_URL;
            }

            String host = uri.getHost();
            if (host == null) {
                return DEFAULT_REDIRECT_URL;
            }

            host = host.toLowerCase();

            boolean isAllowed = false;
            for (String allowedDomain : ALLOWED_DOMAINS) {
                if (host.equals(allowedDomain) || host.endsWith("." + allowedDomain)) {
                    isAllowed = true;
                    break;
                }
            }

            if (!isAllowed) {
                return DEFAULT_REDIRECT_URL;
            }

            return next;

        } catch (URISyntaxException e) {
            return DEFAULT_REDIRECT_URL;
        }
    }
}